TAX_RATE = 0.08

results = []

for item in _items:
    data = item["json"]
    tax_amount = round(data["subtotal"] * TAX_RATE, 2)
    results.append(
        {
            "json": {
                **data,
                "tax_rate": TAX_RATE,
                "tax_amount": tax_amount,
                "total_before_discount": round(data["subtotal"] + tax_amount, 2),
            }
        }
    )

return results

DISCOUNT_THRESHOLD = 40.0
DISCOUNT_PERCENT = 10

results = []

for item in _items:
    data = item["json"]
    total_before = data["total_before_discount"]

    if total_before >= DISCOUNT_THRESHOLD:
        discount_percent = DISCOUNT_PERCENT
        discount_amount = round(total_before * (discount_percent / 100), 2)
    else:
        discount_percent = 0
        discount_amount = 0.0

    results.append(
        {
            "json": {
                **data,
                "discount_percent": discount_percent,
                "discount_amount": discount_amount,
                "final_total": round(total_before - discount_amount, 2),
            }
        }
    )

return results

results = []

for item in _items:
    data = item["json"]
    cycle = int(data.get("cycle", 0))
    next_cycle = cycle + 1

    results.append(
        {
            "json": {
                "cycle": cycle,
                "next_cycle": next_cycle,
                "last_order_id": data.get("order_id"),
                "last_final_total": data.get("final_total"),
                "last_receipt": data.get("receipt"),
                "stage": "loop_ready",
                # This payload becomes the input for Node 1 on the next run.
                "loop_payload": {
                    "cycle": next_cycle,
                    "running": True,
                },
            }
        }
    )

return results
